INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('430', '<p>นาย ก เงินเดือน 24,000 บาท ถ้า นาย ก ฝากเงิน 10% ของเงินเดือนทุกเดือน และเงินเดือนจะขึ้น 3% ในทุกๆ 6 เดือน อยากทราบว่า เมื่อครบ 2 ปี นาย ก มีเงินฝากเท่าไร</p>', '{"A":"112,000 บาท","B":"66,000 บาท","C":"60,200 บาท","D":"57,600 บาท"}', 'C', '<p><strong>ตอบ 3) 60,200 บาท</strong></p><p>เดือนที่ 1 - 6 ; เงินฝาก = 24,000 × (10/100) = 2,400 บาท/เดือน<br/>เดือนที่ 7 - 12 ; เงินเดือนเพิ่ม 3% = 24,000 + (24,000 × 3/100) = 24,720 บาท<br/>&nbsp;&nbsp;&nbsp;&nbsp;เงินฝาก = 24,720 × (10/100) = 2,472 บาท/เดือน<br/>เดือนที่ 13 - 18 ; เงินเดือนเพิ่ม 6% = 24,000 + (24,000 × 6/100) = 25,440 บาท<br/>&nbsp;&nbsp;&nbsp;&nbsp;เงินฝาก = 25,440 × (10/100) = 2,544 บาท/เดือน<br/>เดือนที่ 19 - 24 ; เงินเดือนเพิ่ม 9% = 24,000 + (24,000 × 9/100) = 26,160 บาท<br/>&nbsp;&nbsp;&nbsp;&nbsp;เงินฝาก = 26,160 × (10/100) = 2,616 บาท/เดือน<br/>เมื่อเวลาผ่านไป 2 ปี (24 เดือน) จะมีเงินฝากเท่ากับ:<br/>(2,400 × 6) + (2,472 × 6) + (2,544 × 6) + (2,616 × 6) = 14,400 + 14,832 + 15,264 + 15,696 = 60,192 บาท (ประมาณ <strong>60,200 บาท</strong>)</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["เลขทั่วไป"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('431', '<p>ซื้อของมา 100 ถุง ถุงละ 30 บาท โดยขายราคา 35 บาท จำนวน 20 ถุง และขายในราคา 40 บาท จำนวน 30 ถุง ถ้าต้องการกำไรรวม 35% ถุงที่เหลือต้องขายถุงละกี่บาท</p>', '{"A":"33 บาท","B":"36 บาท","C":"43 บาท","D":"45 บาท"}', 'C', '<p><strong>ตอบ 3) 43 บาท</strong></p><p>ต้นทุน 3,000 บาท ต้องการกำไรรวม 35% = 3,000 × (35/100) = 1,050 บาท<br/>แสดงว่าต้องขายให้ได้เงินทั้งหมด 3,000 + 1,050 = 4,050 บาท<br/>ขายไปแล้ว:<br/>35 บาท จำนวน 20 ถุง = 700 บาท<br/>40 บาท จำนวน 30 ถุง = 1,200 บาท<br/>รวมเป็น 1,900 บาท<br/>เหลืออีก 50 ถุง ต้องขายให้ได้เงินอีก 4,050 - 1,900 = 2,150 บาท<br/>ดังนั้น ต้องขายถุงละ 2,150 / 50 = <strong>43 บาท</strong></p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["เลขทั่วไป"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('432', '<p>นกขายของให้หวานได้กำไร 10% ต่อมาหวานขายต่อไปให้คำนึงได้กำไร 5% คำนึงซื้อมาในราคา 2,310 บาท อยากทราบว่าต้นทุนที่นกซื้อมาเท่าไร</p>', '{"A":"2,000 บาท","B":"2,050 บาท","C":"2,100 บาท","D":"2,310 บาท"}', 'A', '<p><strong>ตอบ 1) 2,000 บาท</strong></p><p>คิดย้อนกลับจากคำนึงไปหาหวาน:<br/>หวานได้กำไร 5% จากทุนของหวาน (ขาย 2,310 บาท)<br/>แสดงว่า 105% = 2,310 บาท<br/>ทุนของหวาน = (2,310 × 100) / 105 = 2,200 บาท<br/><br/>คิดย้อนจากหวานไปหานก:<br/>นกได้กำไร 10% จากทุนของนก (ขายให้หวาน 2,200 บาท)<br/>แสดงว่า 110% = 2,200 บาท<br/>ทุนของนก = (2,200 × 100) / 110 = <strong>2,000 บาท</strong></p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["เลขทั่วไป"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('433', '<p>X = 5Y และ Y = 5X จงหาว่า X มีค่าเท่ากับข้อใด</p>', '{"A":"5","B":"15","C":"0","D":"1"}', 'C', '<p><strong>ตอบ 3) 0</strong></p><p>กำหนดให้ X = 5Y --- (1)<br/>และ Y = 5X --- (2)<br/>นำค่า Y จากสมการ (2) ไปแทนในสมการ (1):<br/>X = 5(5X)<br/>X = 25X<br/>24X = 0<br/>ดังนั้น <strong>X = 0</strong> (และ Y = 0)</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["เลขทั่วไป"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('434', '<p>บริจาคเงินมูลนิธิละ 2,500 บาท จะขาดเงินอยู่ 1,000 บาท หากบริจาคมูลนิธิละ 2,000 บาท จะเหลือเงิน 2,500 บาท อยากทราบว่าจำนวนที่จะบริจาคคือเท่าไร</p>', '{"A":"16,000 บาท","B":"16,500 บาท","C":"17,000 บาท","D":"17,500 บาท"}', 'B', '<p><strong>ตอบ 2) 16,500 บาท</strong></p><p>ให้ X คือจำนวนเงินทั้งหมด<br/>จำนวนมูลนิธิ = (เงินที่มี + เงินที่ขาด) / บริจาคที่ละ<br/>กรณีที่ 1: (X + 1,000) / 2,500 = จำนวนมูลนิธิ<br/>กรณีที่ 2: (X - 2,500) / 2,000 = จำนวนมูลนิธิ<br/>จับสองสมการมาเท่ากัน:<br/>(X + 1,000) / 2,500 = (X - 2,500) / 2,000<br/>คูณไขว้: 2,000(X + 1,000) = 2,500(X - 2,500)<br/>2,000X + 2,000,000 = 2,500X - 6,250,000<br/>500X = 8,250,000<br/>X = <strong>16,500</strong></p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["เลขทั่วไป"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('435', '<p>ปั่นจักรยานสองล้อ ล้อหน้าเส้นผ่าศูนย์กลาง 18 นิ้ว หมุน 30 รอบ/นาที ล้อหลังเส้นผ่าศูนย์กลาง 9 นิ้ว จะหมุนกี่รอบต่อนาที</p>', '{"A":"15 รอบ/นาที","B":"45 รอบ/นาที","C":"60 รอบ/นาที","D":"-"}', 'C', '<p><strong>ตอบ 3) 60 รอบ/นาที</strong></p><p>ระยะทางที่ล้อหน้าหมุน = ระยะทางที่ล้อหลังหมุน<br/>(เส้นรอบวงล้อหน้า × จำนวนรอบล้อหน้า) = (เส้นรอบวงล้อหลัง × จำนวนรอบล้อหลัง)<br/>เนื่องจากเส้นรอบวงแปรผันตรงกับเส้นผ่านศูนย์กลาง (πd)<br/>18 นิ้ว × 30 รอบ = 9 นิ้ว × จำนวนรอบล้อหลัง<br/>540 = 9 × จำนวนรอบล้อหลัง<br/>จำนวนรอบล้อหลัง = 540 / 9 = <strong>60 รอบ/นาที</strong></p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["เลขทั่วไป"]', '2559');
